WASM_RUNTIME_EXPORT_BY_IMPORT: dict[str, str] = {
    import_name: export_name
    for import_name, export_name in WASM_RUNTIME_IMPORT_EXPORT_NAMES
}

WASM_RUNTIME_IMPORT_BY_EXPORT: dict[str, str] = {
    export_name: import_name
    for import_name, export_name in WASM_RUNTIME_IMPORT_EXPORT_NAMES
}

def wasm_runtime_import_name(name: str) -> str | None:
    import_name = wasm_import_name(name)
    if import_name is not None:
        return import_name
    return WASM_RUNTIME_IMPORT_BY_EXPORT.get(name)

def wasm_runtime_export_name(name: str) -> str | None:
    import_name = wasm_runtime_import_name(name)
    if import_name is None:
        return None
    return WASM_RUNTIME_EXPORT_BY_IMPORT[import_name]

def wasm_import_signature(name: str) -> tuple[tuple[str, ...], tuple[str, ...]] | None:
    import_name = wasm_import_name(name)
    if import_name is None:
        return None
    return WASM_IMPORT_SIGNATURE_BY_NAME.get(import_name)

def wasm_import_result_kind(name: str) -> str | None:
    signature = wasm_import_signature(name)
    if signature is None:
        return None
    results = signature[1]
    return "nil" if not results else ", ".join(results)

